```sql
CREATE TABLE LIVRE (
    codeLivre INT PRIMARY KEY,
    titre VARCHAR(255),
    nbPages INT
);

CREATE TABLE AUTEUR (
    codeAuteur INT PRIMARY KEY,
    nom VARCHAR(100),
    prenom VARCHAR(100)
);

CREATE TABLE ECRIT (
    codeLivre INT,
    codeAuteur INT,
    PRIMARY KEY (codeLivre, codeAuteur),
    FOREIGN KEY (codeLivre) REFERENCES LIVRE(codeLivre),
    FOREIGN KEY (codeAuteur) REFERENCES AUTEUR(codeAuteur)
);
```

