```sql
CREATE TABLE LIVRE (
    ISBN VARCHAR(13) PRIMARY KEY,
    titre VARCHAR(255),
    prix DECIMAL(10,2)
);

CREATE TABLE AUTEUR (
    idAuteur INT PRIMARY KEY,
    nom VARCHAR(100)
);

CREATE TABLE ECRIT (
    ISBN VARCHAR(13),
    idAuteur INT,
    PRIMARY KEY (ISBN, idAuteur),
    FOREIGN KEY (ISBN) REFERENCES LIVRE(ISBN),
    FOREIGN KEY (idAuteur) REFERENCES AUTEUR(idAuteur)
);

CREATE TABLE CLIENT (
    idClient INT PRIMARY KEY,
    nom VARCHAR(100),
    email VARCHAR(150)
);

CREATE TABLE COMMANDE (
    numCommande INT PRIMARY KEY,
    dateCommande DATE,
    idClient INT,
    FOREIGN KEY (idClient) REFERENCES CLIENT(idClient)
);

CREATE TABLE LIGNE_COMMANDE (
    numCommande INT,
    ISBN VARCHAR(13),
    quantite INT,
    prixVente DECIMAL(10,2),
    PRIMARY KEY (numCommande, ISBN),
    FOREIGN KEY (numCommande) REFERENCES COMMANDE(numCommande),
    FOREIGN KEY (ISBN) REFERENCES LIVRE(ISBN)
);
```
